const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };

const { randomUUID } = require('node:crypto');

const generateId = () => {
  return randomUUID();
};

module.exports = { generateId };

const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message is required');
  }

  const comment = commentsService.createComment(req.params.projectId, req.params.taskId, message);
  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const comments = commentsService.getCommentsByTask(req.params.projectId, req.params.taskId);
  res.json({ comments });
});

module.exports = router;

const { generateId } = require('../../lib/id');
let commentsStore = {};

const createComment = (projectId, taskId, message) => {
  if (!commentsStore[projectId]) {
    commentsStore[projectId] = {};
  }
  if (!commentsStore[projectId][taskId]) {
    commentsStore[projectId][taskId] = [];
  }

  const commentId = generateId();
  const comment = { id: commentId, message };
  commentsStore[projectId][taskId].push(comment);
  return comment;
};

const getCommentsByTask = (projectId, taskId) => {
  if (!commentsStore[projectId] || !commentsStore[projectId][taskId]) {
    return [];
  }
  return commentsStore[projectId][taskId];
};

module.exports = { createComment, getCommentsByTask };

const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_BODY', 'UserId and role are required');
  }

  const member = membersService.addMember(req.params.projectId, userId, role);
  res.status(201).json({ member });
});

router.get('/', (req, res) => {
  const members = membersService.getMembersByProject(req.params.projectId);
  res.json({ members });
});

module.exports = router;

let membersStore = {};

const addMember = (projectId, userId, role) => {
  if (!membersStore[projectId]) {
    membersStore[projectId] = [];
  }

  const member = { userId, role };
  membersStore[projectId].push(member);
  return member;
};

const getMembersByProject = (projectId) => {
  if (!membersStore[projectId]) {
    return [];
  }
  return membersStore[projectId];
};

module.exports = { addMember, getMembersByProject };

const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }

  const project = projectsService.createProject(name);
  res.status(201).json({ project });
});

router.get('/', (req, res) => {
  const projects = projectsService.getAllProjects();
  res.json({ projects });
});

module.exports = router;

const { generateId } = require('../../lib/id');
let projectsStore = {};

const createProject = (name) => {
  const projectId = generateId();
  const project = { id: projectId, name, tasks: [], members: [] };
  projectsStore[projectId] = project;
  return project;
};

const getAllProjects = () => {
  return Object.values(projectsStore);
};

module.exports = { createProject, getAllProjects };

const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router({ mergeParams: true });

router.post('/', (req, res) => {
  const task = tasksService.createTask(req.params.projectId);
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const { status } = req.query;
  const tasks = tasksService.getTasksByProject(req.params.projectId, status);
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }

  const task = tasksService.updateTask(req.params.projectId, req.params.taskId, status);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }

  res.json({ task });
});

module.exports = router;

const { generateId } = require('../../lib/id');
let projectsStore = {};

const createTask = (projectId) => {
  if (!projectsStore[projectId]) {
    projectsStore[projectId] = { tasks: [] };
  }

  const taskId = generateId();
  const task = { id: taskId, status: 'todo' };
  projectsStore[projectId].tasks.push(task);
  return task;
};

const getTasksByProject = (projectId, status) => {
  if (!projectsStore[projectId]) {
    return [];
  }

  let tasks = projectsStore[projectId].tasks;
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
};

const updateTask = (projectId, taskId, status) => {
  if (!projectsStore[projectId]) {
    return null;
  }

  const taskIndex = projectsStore[projectId].tasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }

  projectsStore[projectId].tasks[taskIndex].status = status;
  return projectsStore[projectId].tasks[taskIndex];
};

module.exports = { createTask, getTasksByProject, updateTask };
